const SabahMap: React.FC = () => {
  const [activeRegion, setActiveRegion] = useState<string | null>(null);
  const [tooltipPositions, setTooltipPositions] = useState<Record<string, TooltipPosition>>({});
  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
  const [showCursor, setShowCursor] = useState(false);
  
  const mapRef = useRef<HTMLDivElement>(null);
  const pathRefs = useRef<Record<string, SVGPathElement | null>>({});

  // Calculate tooltip positions after mount
  useEffect(() => {
    const positions: Record<string, TooltipPosition> = {};
    
    regions.forEach(region => {
      const path = pathRefs.current[region.id];
      if (path) {
        const bbox = path.getBBox();
        positions[region.id] = {
          left: `${((bbox.x + bbox.width / 2) / 800) * 100}%`,
          top: `${((bbox.y + bbox.height / 2) / 800) * 100}%`
        };
      }
    });
    
    setTooltipPositions(positions);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
    if (mapRef.current) {
      const rect = mapRef.current.getBoundingClientRect();
      setCursorPos({
        x: e.clientX - rect.left - 40,
        y: e.clientY - rect.top - 20
      });
    }
  }, []);

  const activateRegion = (id: string) => {
    setActiveRegion(id);
    setShowCursor(true);
  };

  const deactivateRegion = () => {
    setActiveRegion(null);
    setShowCursor(false);
  };

  const activateRegionLegend = (id: string) => {
    setActiveRegion(id);
  };

  const deactivateRegionLegend = () => {
    setActiveRegion(null);
  };

  return (
    <>
      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.5; transform: scale(1.2); }
        }

        .legend-row:hover {
          background-color: rgba(0,0,0,0.05);
          transform: translateX(4px);
        }
      `}</style>
      
      <div className="borneo-app-wrapper" style={styles.wrapper}>
        <div className="map-instruction" style={styles.instructionBox}>
          <div style={styles.instruction}>
            <span className="pulse-icon" style={styles.pulseIcon}></span>
            <p>Select a district on the map to explore destinations</p>
          </div>
        </div>

        <div className="map-flex-layout" style={styles.flexLayout}>
          <div 
            className="map-visual-area" 
            style={styles.visualArea}
            ref={mapRef}
            onMouseMove={handleMouseMove}
          >
            <div className="map-relative-box" style={styles.relativeBox}>
              {/* Cursor Hint */}
              <div 
                id="map-cursor-hint" 
                className="cursor-hint"
                style={{
                  ...styles.cursorHint,
                  left: cursorPos.x,
                  top: cursorPos.y,
                  opacity: showCursor ? 1 : 0,
                  transform: showCursor ? 'translateY(0)' : 'translateY(10px)'
                }}
              >
                Explore
              </div>

              <svg viewBox="0 0 800 800" style={styles.svg}>
                {regions.map(region => (
                  <path
                    key={region.id}
                    ref={(el) => { pathRefs.current[region.id] = el; }}
                    id={`region-${region.id}`}
                    className="region-path"
                    data-color={region.color}
                    d={region.path}
                    style={{
                      ...styles.path,
                      fill: activeRegion === region.id ? region.hoverColor : region.color,
                      strokeWidth: activeRegion === region.id ? 2.5 : 1,
                      stroke: region.strokeColor,
                      filter: activeRegion === region.id ? `drop-shadow(0 0 12px ${region.hoverColor}60)` : 'none',
                      transition: 'fill 0.3s ease, stroke-width 0.3s ease, filter 0.3s ease'
                    }}
                    onMouseEnter={() => activateRegion(region.id)}
                    onMouseLeave={deactivateRegion}
                  />
                ))}
              </svg>

              {/* Tooltips Container */}
              <div className="tooltips-container" style={styles.tooltipsContainer}>
                {regions.map(region => {
                  const pos = tooltipPositions[region.id];
                  const isActive = activeRegion === region.id;
                  
                  return (
                    <div
                      key={`tooltip-${region.id}`}
                      id={`tooltip-${region.id}`}
                      className="borneo-tooltip"
                      style={{
                        ...styles.tooltip,
                        left: pos?.left || '0%',
                        top: pos?.top || '0%',
                        opacity: isActive ? 1 : 0,
                        transform: isActive ? 'translate(-50%, -100%) translateY(-10px)' : 'translate(-50%, -90%)',
                        pointerEvents: 'none'
                      }}
                    >
                      <div style={styles.tooltipHeader}>
                        <div style={{ ...styles.tooltipDot, backgroundColor: region.hoverColor }}></div>
                        <h3 style={styles.tooltipTitle}>{region.name}</h3>
                      </div>
                      <p style={styles.tooltipCountry}>{region.country}</p>
                        <hr style={styles.separator} />
                      <p style={styles.tooltipBody}>{region.description}</p>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Legend Area */}
          <div className="map-legend-area" style={styles.legendArea}>
            <div style={styles.legendCard}>
              <div style={styles.legendSet}>
                  {regions.map(region => (
                    <div
                      key={`legend-${region.id}`}
                      className="legend-row"
                      onMouseEnter={() => activateRegionLegend(region.id)}
                      onMouseLeave={deactivateRegionLegend}
                      data-target={`region-${region.id}`}
                      style={{
                        ...styles.legendRow,
                        backgroundColor: activeRegion === region.id ? 'rgba(0,0,0,0.05)' : 'transparent',
                        transform: activeRegion === region.id ? 'translateX(4px)' : 'translateX(0)'
                      }}
                    >
                      <div style={{ ...styles.legendColor, backgroundColor: region.hoverColor }}></div>
                      <span style={{...styles.legendText, fontWeight: activeRegion === region.id ? 600 : 400}}>{region.name}</span>
                    </div>
                  ))}
              </div>
              
              {/* Information Section */}
              <div style={styles.infoSection}>
                <p style={styles.infoTitle}>
                  <span style={styles.infoIconWrapper}>
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M15 14c.2-1 .7-1.7 1.5-2.5 1-.9 1.5-2.2 1.5-3.5A6 6 0 0 0 6 8c0 1 .2 2.2 1.5 3.5.7.9 1.2 1.5 1.5 2.5"/><path d="M9 18h6"/><path d="M10 22h4"/></svg>
                  </span>
                  Quick Facts
                </p>
                <ul style={{...styles.infoDesc, paddingLeft: '0', margin: 0, listStyle: 'none', display: 'flex', flexDirection: 'column', gap: '0.85rem'}}>
                  <li style={styles.infoListItem}><span style={styles.bullet}>•</span><span>Known as <strong>"Land Below the Wind"</strong>, located just south of the typhoon belt.</span></li>
                  <li style={styles.infoListItem}><span style={styles.bullet}>•</span><span>Home to <strong>Mount Kinabalu</strong>, Malaysia's highest peak at 4,095 meters.</span></li>
                </ul>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

